436→// sync takes a list of potentially duplicated targets, deduplicates them, starts
437→// scrape loops for new targets, and stops scrape loops for disappeared targets.
438→// It returns after all stopped scrape loops terminated.
439→func (sp *scrapePool) sync(targets []*Target) {
440→	uniqueLoops := make(map[uint64]loop)
441→
442→	sp.targetMtx.Lock()
443→	escapingScheme, _ := config.ToEscapingScheme(sp.config.MetricNameEscapingScheme, sp.config.MetricNameValidationScheme)
444→	for _, t := range targets {
445→		hash := t.hash()
446→
447→		if _, ok := sp.activeTargets[hash]; !ok {
448→			// The scrape interval and timeout labels are set to the config's values initially,
449→			// so whether changed via relabeling or not, they'll exist and hold the correct values
450→			// for every target.
451→			var err error
452→			targetInterval, targetTimeout, err := t.intervalAndTimeout(
453→				time.Duration(sp.config.ScrapeInterval),
454→				time.Duration(sp.config.ScrapeTimeout),
455→			)
456→			l := sp.newLoop(scrapeLoopOptions{
457→				target: t,
458→				scraper: &targetScraper{
459→					Target:               t,
460→					client:               sp.client,
461→					timeout:              targetTimeout,
462→					bodySizeLimit:        int64(sp.config.BodySizeLimit),
463→					acceptHeader:         acceptHeader(sp.config.ScrapeProtocols, escapingScheme),
464→					acceptEncodingHeader: acceptEncodingHeader(sp.config.EnableCompression),
465→					metrics:              sp.metrics,
466→				},
467→				cache:    newScrapeCache(sp.metrics),
468→				interval: targetInterval,
469→				timeout:  targetTimeout,
470→				sp:       sp,
471→			})
472→			if err != nil {
473→				l.setForcedError(err)
474→			}
475→			l.setScrapeFailureLogger(sp.scrapeFailureLogger)
476→
477→			sp.activeTargets[hash] = t
478→			sp.loops[hash] = l
479→
480→			uniqueLoops[hash] = l
481→		} else {
482→			// This might be a duplicated target.
483→			if _, ok := uniqueLoops[hash]; !ok {
484→				uniqueLoops[hash] = nil
485→			}
486→			// Need to keep the most updated ScrapeConfig for
487→			// displaying labels in the Service Discovery web page.
488→			sp.activeTargets[hash].SetScrapeConfig(sp.config, t.tLabels, t.tgLabels)
489→		}
490→	}
491→
492→	var wg sync.WaitGroup
493→
494→	// Stop and remove old targets and scraper loops.
495→	for hash := range sp.activeTargets {
496→		if _, ok := uniqueLoops[hash]; !ok {
497→			wg.Add(1)
498→			go func(l loop) {
499→				l.stop()
500→				wg.Done()
501→			}(sp.loops[hash])
502→
503→			delete(sp.loops, hash)
504→			delete(sp.activeTargets, hash)
505→		}
506→	}
507→
508→	sp.targetMtx.Unlock()
509→
510→	sp.metrics.targetScrapePoolTargetsAdded.WithLabelValues(sp.config.JobName).Set(float64(len(uniqueLoops)))
511→	forcedErr := sp.refreshTargetLimitErr()
512→	for _, l := range sp.loops {
513→		l.setForcedError(forcedErr)
514→	}
515→	for _, l := range uniqueLoops {
516→		if l != nil {
517→			go l.run(nil)
518→		}
519→	}
520→	// Wait for all potentially stopped scrapers to terminate.
521→	// This covers the case of flapping targets. If the server is under high load, a new scraper
522→	// may be active and tries to insert. The old scraper that didn't terminate yet could still
523→	// be inserting a previous sample set.
524→	wg.Wait()
525→}
