527→// refreshTargetLimitErr returns an error that can be passed to the scrape loops
528→// if the number of targets exceeds the configured limit.
529→func (sp *scrapePool) refreshTargetLimitErr() error {
530→	if sp.config == nil || sp.config.TargetLimit == 0 {
531→		return nil
532→	}
533→	if l := len(sp.activeTargets); l > int(sp.config.TargetLimit) {
534→		sp.metrics.targetScrapePoolExceededTargetLimit.Inc()
535→		return fmt.Errorf("target_limit exceeded (number of targets: %d, limit: %d)", l, sp.config.TargetLimit)
536→	}
537→	return nil
538→}
