550→func verifyLabelLimits(lset labels.Labels, limits *labelLimits) error {
551→	if limits == nil {
552→		return nil
553→	}
554→
555→	met := lset.Get(model.MetricNameLabel)
556→	if limits.labelLimit > 0 {
557→		nbLabels := lset.Len()
558→		if nbLabels > limits.labelLimit {
559→			return fmt.Errorf("label_limit exceeded (metric: %.50s, number of labels: %d, limit: %d)", met, nbLabels, limits.labelLimit)
560→		}
561→	}
562→
563→	if limits.labelNameLengthLimit == 0 && limits.labelValueLengthLimit == 0 {
564→		return nil
565→	}
566→
567→	return lset.Validate(func(l labels.Label) error {
568→		if limits.labelNameLengthLimit > 0 {
569→			nameLength := len(l.Name)
570→			if nameLength > limits.labelNameLengthLimit {
571→				return fmt.Errorf("label_name_length_limit exceeded (metric: %.50s, label name: %.50s, length: %d, limit: %d)", met, l.Name, nameLength, limits.labelNameLengthLimit)
572→			}
573→		}
574→
575→		if limits.labelValueLengthLimit > 0 {
576→			valueLength := len(l.Value)
577→			if valueLength > limits.labelValueLengthLimit {
578→				return fmt.Errorf("label_value_length_limit exceeded (metric: %.50s, label name: %.50s, value: %.50q, length: %d, limit: %d)", met, l.Name, l.Value, valueLength, limits.labelValueLengthLimit)
579→			}
580→		}
581→		return nil
582→	})
583→}
