 77→func (s Series) String() string {
 78→	// TODO(beorn7): This currently renders floats first and then
 79→	// histograms, each sorted by timestamp. Maybe, in mixed series, that's
 80→	// fine. Maybe, however, primary sorting by timestamp is preferred, in
 81→	// which case this has to be changed.
 82→	vals := make([]string, 0, len(s.Floats)+len(s.Histograms))
 83→	for _, f := range s.Floats {
 84→		vals = append(vals, f.String())
 85→	}
 86→	for _, h := range s.Histograms {
 87→		vals = append(vals, h.String())
 88→	}
 89→	return fmt.Sprintf("%s =>\n%s", s.Metric, strings.Join(vals, "\n"))
 90→}
