 92→// FPoint represents a single float data point for a given timestamp.
 93→type FPoint struct {
 94→	T int64
 95→	F float64
 96→}
 97→
 98→func (p FPoint) String() string {
 99→	s := strconv.FormatFloat(p.F, 'f', -1, 64)
100→	return fmt.Sprintf("%s @[%v]", s, p.T)
