117→// HPoint represents a single histogram data point for a given timestamp.
118→// H must never be nil.
119→type HPoint struct {
120→	T int64
121→	H *histogram.FloatHistogram
122→}
123→
124→func (p HPoint) String() string {
125→	return fmt.Sprintf("%s @[%v]", p.H.String(), p.T)
