 937→func (c *scrapeCache) iterDone(flushCache bool) {
 938→	c.metaMtx.Lock()
 939→	count := len(c.series) + len(c.droppedSeries) + len(c.metadata)
 940→	c.metaMtx.Unlock()
 941→
 942→	switch {
 943→	case flushCache:
 944→		c.successfulCount = count
 945→	case count > c.successfulCount*2+1000:
 946→		// If a target had varying labels in scrapes that ultimately failed,
 947→		// the caches would grow indefinitely. Force a flush when this happens.
 948→		// We use the heuristic that this is a doubling of the cache size
 949→		// since the last scrape, and allow an additional 1000 in case
 950→		// initial scrapes all fail.
 951→		flushCache = true
 952→		c.metrics.targetScrapeCacheFlushForced.Inc()
 953→	}
 954→
 955→	if flushCache {
 956→		// All caches may grow over time through series churn
 957→		// or multiple string representations of the same metric. Clean up entries
 958→		// that haven't appeared in the last scrape.
 959→		for s, e := range c.series {
 960→			if c.iter != e.lastIter {
 961→				delete(c.series, s)
 962→			}
 963→		}
 964→		for s, iter := range c.droppedSeries {
 965→			if c.iter != *iter {
 966→				delete(c.droppedSeries, s)
 967→			}
 968→		}
 969→		c.metaMtx.Lock()
 970→		for m, e := range c.metadata {
 971→			// Keep metadata around for 10 scrapes after its metric disappeared.
 972→			if c.iter-e.lastIter > 10 {
 973→				delete(c.metadata, m)
 974→			}
 975→		}
 976→		c.metaMtx.Unlock()
 977→	}
 978→
 979→	// Swap current and previous series then clear the new current, to save allocations.
 980→	c.seriesPrev, c.seriesCur = c.seriesCur, c.seriesPrev
 981→	clear(c.seriesCur)
 982→
 983→	c.iter++
 984→}
