1301→func (sl *scrapeLoop) appender() scrapeLoopAppendAdapter {
1302→	if sl.appendableV2 != nil {
1303→		return &scrapeLoopAppenderV2{scrapeLoop: sl, AppenderV2: sl.appendableV2.AppenderV2(sl.appenderCtx)}
1304→	}
1305→	return &scrapeLoopAppender{scrapeLoop: sl, Appender: sl.appendable.Appender(sl.appenderCtx)}
