1308→// scrapeAndReport performs a scrape and then appends the result to the storage
1309→// together with reporting metrics, by using as few appenders as possible.
1310→// In the happy scenario, a single appender is used.
1311→// This function uses sl.appenderCtx instead of sl.ctx on purpose. A scrape should
1312→// only be cancelled on shutdown, not on reloads.
1313→func (sl *scrapeLoop) scrapeAndReport(last, appendTime time.Time, errc chan<- error) time.Time {
1314→	start := time.Now()
1315→
1316→	// Only record after the first scrape.
1317→	if !last.IsZero() {
1318→		sl.metrics.targetIntervalLength.WithLabelValues(sl.interval.String()).Observe(
1319→			time.Since(last).Seconds(),
1320→		)
1321→		sl.metrics.targetIntervalLengthHistogram.WithLabelValues(sl.interval.String()).Observe(
1322→			time.Since(last).Seconds(),
1323→		)
1324→	}
1325→
1326→	var total, added, seriesAdded, bytesRead int
1327→	var err, appErr, scrapeErr error
1328→
1329→	app := sl.appender()
1330→	defer func() {
1331→		if err != nil {
1332→			_ = app.Rollback()
1333→			return
1334→		}
1335→		err = app.Commit()
1336→		if sl.reportExtraMetrics {
1337→			totalDuration := time.Since(start)
1338→			// Record total scrape duration metric.
1339→			sl.metrics.targetScrapeDuration.Observe(totalDuration.Seconds())
1340→		}
1341→		if err != nil {
1342→			sl.l.Error("Scrape commit failed", "err", err)
1343→		}
1344→	}()
1345→
1346→	defer func() {
1347→		if err = sl.report(app, appendTime, time.Since(start), total, added, seriesAdded, bytesRead, scrapeErr); err != nil {
1348→			sl.l.Warn("Appending scrape report failed", "err", err)
1349→		}
1350→	}()
1351→
1352→	if forcedErr := sl.getForcedError(); forcedErr != nil {
1353→		scrapeErr = forcedErr
1354→		// Add stale markers.
1355→		if _, _, _, err := app.append([]byte{}, "", appendTime); err != nil {
1356→			_ = app.Rollback()
1357→			app = sl.appender()
1358→			sl.l.Warn("Append failed", "err", err)
1359→		}
1360→		if errc != nil {
1361→			select {
1362→			case errc <- forcedErr:
1363→			case <-sl.ctx.Done():
1364→			}
1365→		}
1366→
1367→		return start
1368→	}
1369→
1370→	var contentType string
1371→	var resp *http.Response
1372→	var b []byte
1373→	var buf *bytes.Buffer
1374→	scrapeCtx, cancel := context.WithTimeout(sl.parentCtx, sl.timeout)
1375→	resp, scrapeErr = sl.scraper.scrape(scrapeCtx)
1376→	if scrapeErr == nil {
1377→		b = sl.buffers.Get(sl.lastScrapeSize).([]byte)
1378→		defer sl.buffers.Put(b)
1379→		buf = bytes.NewBuffer(b)
1380→		contentType, scrapeErr = sl.scraper.readResponse(scrapeCtx, resp, buf)
1381→	}
1382→	cancel()
1383→
1384→	if scrapeErr == nil {
1385→		b = buf.Bytes()
1386→		// NOTE: There were issues with misbehaving clients in the past
1387→		// that occasionally returned empty results. We don't want those
1388→		// to falsely reset our buffer size.
1389→		if len(b) > 0 {
1390→			sl.lastScrapeSize = len(b)
1391→		}
1392→		bytesRead = len(b)
1393→	} else {
1394→		sl.l.Debug("Scrape failed", "err", scrapeErr)
1395→		sl.scrapeFailureLoggerMtx.RLock()
1396→		if sl.scrapeFailureLogger != nil {
1397→			slog.New(sl.scrapeFailureLogger).Error(scrapeErr.Error())
1398→		}
1399→		sl.scrapeFailureLoggerMtx.RUnlock()

1400→		if errc != nil {
1401→			select {
1402→			case errc <- scrapeErr:
1403→			case <-sl.ctx.Done():
1404→			}
1405→		}
1406→		if errors.Is(scrapeErr, errBodySizeLimit) {
1407→			bytesRead = -1
1408→		}
1409→	}
1410→
1411→	// A failed scrape is the same as an empty scrape,
1412→	// we still call sl.append to trigger stale markers.
1413→	total, added, seriesAdded, appErr = app.append(b, contentType, appendTime)
1414→	if appErr != nil {
1415→		_ = app.Rollback()
1416→		app = sl.appender()
1417→		sl.l.Debug("Append failed", "err", appErr)
1418→		// The append failed, probably due to a parse error or sample limit.
1419→		// Call sl.append again with an empty scrape to trigger stale markers.
1420→		if _, _, _, err := app.append([]byte{}, "", appendTime); err != nil {
1421→			_ = app.Rollback()
1422→			app = sl.appender()
1423→			sl.l.Warn("Append failed", "err", err)
1424→		}
1425→	}
1426→
1427→	if scrapeErr == nil {
1428→		scrapeErr = appErr
1429→	}
1430→
1431→	return start
1432→}
