1446→func (sl *scrapeLoop) endOfRunStaleness(last time.Time, ticker *time.Ticker, interval time.Duration) {
1447→	// Scraping has stopped. We want to write stale markers but
1448→	// the target may be recreated, so we wait just over 2 scrape intervals
1449→	// before creating them.
1450→	// If the context is canceled, we presume the server is shutting down
1451→	// and will restart where is was. We do not attempt to write stale markers
1452→	// in this case.
1453→
1454→	if last.IsZero() {
1455→		// There never was a scrape, so there will be no stale markers.
1456→		return
1457→	}
1458→
1459→	// Wait for when the next scrape would have been, record its timestamp.
1460→	var staleTime time.Time
1461→	select {
1462→	case <-sl.parentCtx.Done():
1463→		return
1464→	case <-ticker.C:
1465→		staleTime = time.Now()
1466→	}
1467→
1468→	// Wait for when the next scrape would have been, if the target was recreated
1469→	// samples should have been ingested by now.
1470→	select {
1471→	case <-sl.parentCtx.Done():
1472→		return
1473→	case <-ticker.C:
1474→	}
1475→
1476→	// Wait for an extra 10% of the interval, just to be safe.
1477→	select {
1478→	case <-sl.parentCtx.Done():
1479→		return
1480→	case <-time.After(interval / 10):
1481→	}
1482→
1483→	// Check if end-of-run staleness markers have been disabled while we were waiting.
1484→	if sl.disabledEndOfRunStalenessMarkers.Load() {
1485→		return
1486→	}
1487→
1488→	// Call sl.append again with an empty scrape to trigger stale markers.
1489→	// If the target has since been recreated and scraped, the
1490→	// stale markers will be out of order and ignored.
1491→	// sl.context would have been cancelled, hence using sl.appenderCtx.
1492→	app := sl.appender()
1493→	var err error
1494→	defer func() {
1495→		if err != nil {
1496→			_ = app.Rollback()
1497→			return
1498→		}
1499→		err = app.Commit()
1500→		if err != nil {
1501→			sl.l.Warn("Stale commit failed", "err", err)
1502→		}
1503→	}()
1504→	if _, _, _, err = app.append([]byte{}, "", staleTime); err != nil {
1505→		_ = app.Rollback()
1506→		app = sl.appender()
1507→		sl.l.Warn("Stale append failed", "err", err)
1508→	}
1509→	if err = sl.reportStale(app, staleTime); err != nil {
1510→		sl.l.Warn("Stale report failed", "err", err)
1511→	}
1512→}
1513→
1514→// Stop the scraping. May still write data and stale markers after it has
1515→// returned. Cancel the context to stop all writes.
1516→func (sl *scrapeLoop) stop() {
1517→	sl.cancel()
1518→	<-sl.stopped
1519→}
