1529→type appendErrors struct {
1530→	numOutOfOrder         int
1531→	numDuplicates         int
1532→	numOutOfBounds        int
1533→	numExemplarOutOfOrder int
1534→}
1535→
1536→// Update the stale markers.
1537→func (sl *scrapeLoop) updateStaleMarkers(app storage.Appender, defTime int64) (err error) {
1538→	sl.cache.forEachStale(func(ref storage.SeriesRef, lset labels.Labels) bool {
1539→		// Series no longer exposed, mark it stale.
1540→		app.SetOptions(&aOptionRejectEarlyOOO)
1541→		_, err = app.Append(ref, lset, defTime, math.Float64frombits(value.StaleNaN))
1542→		app.SetOptions(nil)
1543→		switch {
1544→		case errors.Is(err, storage.ErrOutOfOrderSample), errors.Is(err, storage.ErrDuplicateSampleForTimestamp):
1545→			// Do not count these in logging, as this is expected if a target
1546→			// goes away and comes back again with a new scrape loop.
1547→			err = nil
1548→		}
1549→		return err == nil
1550→	})
1551→	return err
1552→}
