1560→var _ scrapeLoopAppendAdapter = &scrapeLoopAppender{}
1561→
1562→func (sl *scrapeLoopAppender) append(b []byte, contentType string, ts time.Time) (total, added, seriesAdded int, err error) {
1563→	defTime := timestamp.FromTime(ts)
1564→
1565→	if len(b) == 0 {
1566→		// Empty scrape. Just update the stale makers and swap the cache (but don't flush it).
1567→		err = sl.updateStaleMarkers(sl.Appender, defTime)
1568→		sl.cache.iterDone(false)
1569→		return total, added, seriesAdded, err
1570→	}
1571→
1572→	p, err := textparse.New(b, contentType, sl.symbolTable, textparse.ParserOptions{
1573→		EnableTypeAndUnitLabels:                 sl.enableTypeAndUnitLabels,
1574→		IgnoreNativeHistograms:                  !sl.enableNativeHistogramScraping,
1575→		ConvertClassicHistogramsToNHCB:          sl.convertClassicHistToNHCB,
1576→		KeepClassicOnClassicAndNativeHistograms: sl.alwaysScrapeClassicHist,
1577→		OpenMetricsSkipSTSeries:                 sl.enableSTZeroIngestion,
1578→		FallbackContentType:                     sl.fallbackScrapeProtocol,
1579→	})
1580→	if p == nil {
1581→		sl.l.Error(
1582→			"Failed to determine correct type of scrape target.",
1583→			"content_type", contentType,
1584→			"fallback_media_type", sl.fallbackScrapeProtocol,
1585→			"err", err,
1586→		)
1587→		return total, added, seriesAdded, err
1588→	}
1589→	if err != nil {
1590→		sl.l.Debug(
1591→			"Invalid content type on scrape, using fallback setting.",
1592→			"content_type", contentType,
1593→			"fallback_media_type", sl.fallbackScrapeProtocol,
1594→			"err", err,
1595→		)
1596→	}
1597→	var (
1598→		appErrs        = appendErrors{}
1599→		sampleLimitErr error
1600→		bucketLimitErr error
1601→		lset           labels.Labels     // Escapes to heap so hoisted out of loop.
1602→		e              exemplar.Exemplar // Escapes to heap so hoisted out of loop.
1603→		lastMeta       *metaEntry
1604→		lastMFName     []byte
1605→	)
1606→
1607→	exemplars := make([]exemplar.Exemplar, 0, 1)
1608→
1609→	// Take an appender with limits.
1610→	app := appenderWithLimits(sl.Appender, sl.sampleLimit, sl.bucketLimit, sl.maxSchema)
1611→
1612→	defer func() {
1613→		if err != nil {
1614→			return
1615→		}
1616→		// Flush and swap the cache as the scrape was non-empty.
1617→		sl.cache.iterDone(true)
1618→	}()
1619→
1620→loop:
1621→	for {
1622→		var (
1623→			et                       textparse.Entry
1624→			sampleAdded, isHistogram bool
1625→			met                      []byte
1626→			parsedTimestamp          *int64
1627→			val                      float64
1628→			h                        *histogram.Histogram
1629→			fh                       *histogram.FloatHistogram
1630→		)
1631→		if et, err = p.Next(); err != nil {
1632→			if errors.Is(err, io.EOF) {
1633→				err = nil
1634→			}
1635→			break
1636→		}
1637→		switch et {
1638→		// TODO(bwplotka): Consider changing parser to give metadata at once instead of type, help and unit in separation, ideally on `Series()/Histogram()`
1639→		// otherwise we can expose metadata without series on metadata API.
1640→		case textparse.EntryType:
1641→			// TODO(bwplotka): Build meta entry directly instead of locking and updating the map. This will
1642→			// allow to properly update metadata when e.g unit was added, then removed;
1643→			lastMFName, lastMeta = sl.cache.setType(p.Type())
1644→			continue
1645→		case textparse.EntryHelp:
1646→			lastMFName, lastMeta = sl.cache.setHelp(p.Help())
1647→			continue
1648→		case textparse.EntryUnit:
1649→			lastMFName, lastMeta = sl.cache.setUnit(p.Unit())
1650→			continue
1651→		case textparse.EntryComment:
1652→			continue
1653→		case textparse.EntryHistogram:
1654→			isHistogram = true
1655→		default:
1656→		}
1657→		total++
1658→
1659→		t := defTime
1660→		if isHistogram {
1661→			met, parsedTimestamp, h, fh = p.Histogram()
1662→		} else {
1663→			met, parsedTimestamp, val = p.Series()
1664→		}
1665→		if !sl.honorTimestamps {
1666→			parsedTimestamp = nil
1667→		}
1668→		if parsedTimestamp != nil {
1669→			t = *parsedTimestamp
1670→		}
1671→
1672→		if sl.cache.getDropped(met) {
1673→			continue
1674→		}
1675→		ce, seriesCached, seriesAlreadyScraped := sl.cache.get(met)
1676→		var (
1677→			ref  storage.SeriesRef
1678→			hash uint64
1679→		)
1680→
1681→		if seriesCached {
1682→			ref = ce.ref
1683→			lset = ce.lset
1684→			hash = ce.hash
1685→		} else {
1686→			p.Labels(&lset)
1687→			hash = lset.Hash()
1688→
1689→			// Hash label set as it is seen local to the target. Then add target labels
1690→			// and relabeling and store the final label set.
1691→			lset = sl.sampleMutator(lset)
1692→
1693→			// The label set may be set to empty to indicate dropping.
1694→			if lset.IsEmpty() {
1695→				sl.cache.addDropped(met)
1696→				continue
1697→			}
1698→
1699→			if !lset.Has(model.MetricNameLabel) {
1700→				err = errNameLabelMandatory
1701→				break loop
1702→			}
1703→			if !lset.IsValid(sl.validationScheme) {
1704→				err = fmt.Errorf("invalid metric name or label names: %s", lset.String())
1705→				break loop
1706→			}
1707→
1708→			// If any label limits is exceeded the scrape should fail.
1709→			if err = verifyLabelLimits(lset, sl.labelLimits); err != nil {
1710→				sl.metrics.targetScrapePoolExceededLabelLimits.Inc()
1711→				break loop
1712→			}
1713→		}
1714→
1715→		if seriesAlreadyScraped && parsedTimestamp == nil {
1716→			err = storage.ErrDuplicateSampleForTimestamp
1717→		} else {
1718→			if sl.enableSTZeroIngestion {
1719→				if stMs := p.StartTimestamp(); stMs != 0 {
1720→					if isHistogram {
1721→						if h != nil {
1722→							ref, err = app.AppendHistogramSTZeroSample(ref, lset, t, stMs, h, nil)
1723→						} else {
1724→							ref, err = app.AppendHistogramSTZeroSample(ref, lset, t, stMs, nil, fh)
1725→						}
1726→					} else {
1727→						ref, err = app.AppendSTZeroSample(ref, lset, t, stMs)
1728→					}
1729→					if err != nil && !errors.Is(err, storage.ErrOutOfOrderST) { // OOO is a common case, ignoring completely for now.
1730→						// ST is an experimental feature. For now, we don't need to fail the
1731→						// scrape on errors updating the created timestamp, log debug.
1732→						sl.l.Debug("Error when appending ST in scrape loop", "series", string(met), "ct", stMs, "t", t, "err", err)
1733→					}
1734→				}
1735→			}
1736→
1737→			if isHistogram {
1738→				if h != nil {
1739→					ref, err = app.AppendHistogram(ref, lset, t, h, nil)
1740→				} else {
1741→					ref, err = app.AppendHistogram(ref, lset, t, nil, fh)
1742→				}
1743→			} else {
1744→				ref, err = app.Append(ref, lset, t, val)
1745→			}
1746→		}
1747→
1748→		if err == nil {
1749→			if (parsedTimestamp == nil || sl.trackTimestampsStaleness) && ce != nil {
1750→				sl.cache.trackStaleness(ce.ref, ce)
1751→			}
1752→		}
1753→
1754→		sampleAdded, err = sl.checkAddError(met, nil, err, &sampleLimitErr, &bucketLimitErr, &appErrs)
1755→		if err != nil {
1756→			if !errors.Is(err, storage.ErrNotFound) {
1757→				sl.l.Debug("Unexpected error", "series", string(met), "err", err)
1758→			}
1759→			break loop
1760→		}
1761→
1762→		// If series wasn't cached (is new, not seen on previous scrape) we need need to add it to the scrape cache.
1763→		// But we only do this for series that were appended to TSDB without errors.
1764→		// If a series was new but we didn't append it due to sample_limit or other errors then we don't need
1765→		// it in the scrape cache because we don't need to emit StaleNaNs for it when it disappears.
1766→		if !seriesCached && sampleAdded {
1767→			ce = sl.cache.addRef(met, ref, lset, hash)
1768→			if ce != nil && (parsedTimestamp == nil || sl.trackTimestampsStaleness) {
1769→				// Bypass staleness logic if there is an explicit timestamp.
1770→				// But make sure we only do this if we have a cache entry (ce) for our series.
1771→				sl.cache.trackStaleness(ref, ce)
1772→			}
1773→			if sampleLimitErr == nil && bucketLimitErr == nil {
1774→				seriesAdded++
1775→			}
1776→		}
1777→
1778→		// Increment added even if there's an error so we correctly report the
1779→		// number of samples remaining after relabeling.
1780→		// We still report duplicated samples here since this number should be the exact number
1781→		// of time series exposed on a scrape after relabelling.
1782→		added++
1783→		exemplars = exemplars[:0] // Reset and reuse the exemplar slice.
1784→		for hasExemplar := p.Exemplar(&e); hasExemplar; hasExemplar = p.Exemplar(&e) {
1785→			if !e.HasTs {
1786→				if isHistogram {
1787→					// We drop exemplars for native histograms if they don't have a timestamp.
1788→					// Missing timestamps are deliberately not supported as we want to start
1789→					// enforcing timestamps for exemplars as otherwise proper deduplication
1790→					// is inefficient and purely based on heuristics: we cannot distinguish
1791→					// between repeated exemplars and new instances with the same values.
1792→					// This is done silently without logs as it is not an error but out of spec.
1793→					// This does not affect classic histograms so that behaviour is unchanged.
1794→					e = exemplar.Exemplar{} // Reset for next time round loop.
1795→					continue
1796→				}
1797→				e.Ts = t
1798→			}
1799→			exemplars = append(exemplars, e)
1800→			e = exemplar.Exemplar{} // Reset for next time round loop.
1801→		}
1802→		// Sort so that checking for duplicates / out of order is more efficient during validation.
1803→		slices.SortFunc(exemplars, exemplar.Compare)
1804→		outOfOrderExemplars := 0
1805→		for _, e := range exemplars {
1806→			_, exemplarErr := app.AppendExemplar(ref, lset, e)
1807→			switch {
1808→			case exemplarErr == nil:
1809→				// Do nothing.
1810→			case errors.Is(exemplarErr, storage.ErrOutOfOrderExemplar):
1811→				outOfOrderExemplars++
1812→			default:
1813→				// Since exemplar storage is still experimental, we don't fail the scrape on ingestion errors.
1814→				sl.l.Debug("Error while adding exemplar in AddExemplar", "exemplar", fmt.Sprintf("%+v", e), "err", exemplarErr)
1815→			}
1816→		}
1817→		if outOfOrderExemplars > 0 && outOfOrderExemplars == len(exemplars) {
1818→			// Only report out of order exemplars if all are out of order, otherwise this was a partial update
1819→			// to some existing set of exemplars.
1820→			appErrs.numExemplarOutOfOrder += outOfOrderExemplars
1821→			sl.l.Debug("Out of order exemplars", "count", outOfOrderExemplars, "latest", fmt.Sprintf("%+v", exemplars[len(exemplars)-1]))
1822→			sl.metrics.targetScrapeExemplarOutOfOrder.Add(float64(outOfOrderExemplars))
1823→		}
1824→
1825→		if sl.appendMetadataToWAL && lastMeta != nil {
1826→			// Is it new series OR did metadata change for this family?
1827→			if !seriesCached || lastMeta.lastIterChange == sl.cache.iter {
1828→				// In majority cases we can trust that the current series/histogram is matching the lastMeta and lastMFName.
1829→				// However, optional TYPE etc metadata and broken OM text can break this, detect those cases here.
1830→				// TODO(https://github.com/prometheus/prometheus/issues/17900): Move this to text and OM parser.
1831→				if isSeriesPartOfFamily(lset.Get(model.MetricNameLabel), lastMFName, lastMeta.Type) {
1832→					if _, merr := app.UpdateMetadata(ref, lset, lastMeta.Metadata); merr != nil {
1833→						// No need to fail the scrape on errors appending metadata.
1834→						sl.l.Debug("Error when appending metadata in scrape loop", "ref", fmt.Sprintf("%d", ref), "metadata", fmt.Sprintf("%+v", lastMeta.Metadata), "err", merr)
1835→					}
1836→				}
1837→			}
1838→		}
1839→	}
1840→	if sampleLimitErr != nil {
1841→		if err == nil {
1842→			err = sampleLimitErr
1843→		}
1844→		// We only want to increment this once per scrape, so this is Inc'd outside the loop.
1845→		sl.metrics.targetScrapeSampleLimit.Inc()
1846→	}
1847→	if bucketLimitErr != nil {
1848→		if err == nil {
1849→			err = bucketLimitErr // If sample limit is hit, that error takes precedence.
1850→		}
1851→		// We only want to increment this once per scrape, so this is Inc'd outside the loop.
1852→		sl.metrics.targetScrapeNativeHistogramBucketLimit.Inc()
1853→	}
1854→	if appErrs.numOutOfOrder > 0 {
1855→		sl.l.Warn("Error on ingesting out-of-order samples", "num_dropped", appErrs.numOutOfOrder)
1856→	}
1857→	if appErrs.numDuplicates > 0 {
1858→		sl.l.Warn("Error on ingesting samples with different value but same timestamp", "num_dropped", appErrs.numDuplicates)
1859→	}
1860→	if appErrs.numOutOfBounds > 0 {
1861→		sl.l.Warn("Error on ingesting samples that are too old or are too far into the future", "num_dropped", appErrs.numOutOfBounds)
1862→	}
1863→	if appErrs.numExemplarOutOfOrder > 0 {
1864→		sl.l.Warn("Error on ingesting out-of-order exemplars", "num_dropped", appErrs.numExemplarOutOfOrder)
1865→	}
1866→	if err == nil {
1867→		err = sl.updateStaleMarkers(app, defTime)
1868→	}
1869→	return total, added, seriesAdded, err
1870→}
1871→
1872→// TODO(https://github.com/prometheus/prometheus/issues/17900): Move this to text and OM parser.
1873→func isSeriesPartOfFamily(mName string, mfName []byte, typ model.MetricType) bool {
1874→	mfNameStr := yoloString(mfName)
1875→	if !strings.HasPrefix(mName, mfNameStr) { // Fast path.
1876→		return false
1877→	}
1878→
1879→	var (
1880→		gotMFName string
1881→		ok        bool
1882→	)
1883→	switch typ {
1884→	case model.MetricTypeCounter:
1885→		// Prometheus allows _total, cut it from mf name to support this case.
1886→		mfNameStr, _ = strings.CutSuffix(mfNameStr, "_total")
1887→
1888→		gotMFName, ok = strings.CutSuffix(mName, "_total")
1889→		if !ok {
1890→			gotMFName = mName
1891→		}
1892→	case model.MetricTypeHistogram:
1893→		gotMFName, ok = strings.CutSuffix(mName, "_bucket")
1894→		if !ok {
1895→			gotMFName, ok = strings.CutSuffix(mName, "_sum")
1896→			if !ok {
1897→				gotMFName, ok = strings.CutSuffix(mName, "_count")
1898→				if !ok {
1899→					gotMFName = mName
